class Solution {
public:
    vector<int> smallestTrimmedNumbers(vector<string>& nums, vector<vector<int>>& queries) {
        vector<int> answer;
        for (auto& query : queries) {
            int k = query[0], trim = query[1];
            vector<pair<int, int>> trimmed;
            for (int i = 0; i < nums.size(); i++) {
                string s = nums[i];
                string trimmedStr = s.substr(s.size() - trim);
                trimmed.push_back({stoi(trimmedStr), i});
            }
            sort(trimmed.begin(), trimmed.end());
            answer.push_back(trimmed[k - 1].second);
        }
        return answer;
    }
};
